import androidx.room.withTransaction
import com.eaglepoint.task136.shared.db.AppDatabase
import com.eaglepoint.task136.shared.db.OrderEntity
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.filterNotNull
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.launch
import kotlinx.datetime.Clock
import kotlin.time.Duration.Companion.minutes

enum class OrderState {
    Draft,
    PendingTender,
    Confirmed,
    Cancelled,
    Expired,
}

class OrderStateMachine(
    private val database: AppDatabase,
    private val clock: Clock,
) {
    private val scope = CoroutineScope(SupervisorJob() + Dispatchers.Default)

    fun observeState(orderId: String): Flow<OrderState> {
        return database.orderDao().observeById(orderId)
            .filterNotNull()
            .map { OrderState.valueOf(it.state) }
    }

    suspend fun transitionToPendingTender(orderId: String) {
        val now = clock.now().toEpochMilliseconds()
        val expiresAt = clock.now().plus(30.minutes).toEpochMilliseconds()

        database.withTransaction {
            val order = database.orderDao().getById(orderId) ?: return@withTransaction
            val pending = order.copy(state = OrderState.PendingTender.name, expiresAt = expiresAt)
            database.orderDao().update(pending)

            val resource = database.resourceDao().getById(order.resourceId)
            if (resource != null) {
                database.resourceDao().update(resource.copy(availableUnits = (resource.availableUnits - order.quantity).coerceAtLeast(0)))
            }
        }

        scope.launch {
            delay(30.minutes)
            database.withTransaction {
                val latest = database.orderDao().getById(orderId) ?: return@withTransaction
                if (latest.state == OrderState.PendingTender.name && (latest.expiresAt ?: now) <= clock.now().toEpochMilliseconds()) {
                    database.orderDao().update(latest.copy(state = OrderState.Expired.name))
                    restockInventory(latest)
                }
            }
        }
    }

    suspend fun confirm(orderId: String) {
        database.withTransaction {
            val latest = database.orderDao().getById(orderId) ?: return@withTransaction
            database.orderDao().update(latest.copy(state = OrderState.Confirmed.name, expiresAt = null))
        }
    }

    private suspend fun restockInventory(order: OrderEntity) {
        val resource = database.resourceDao().getById(order.resourceId) ?: return
        database.resourceDao().update(resource.copy(availableUnits = resource.availableUnits + order.quantity))
    }
}

package com.eaglepoint.task136.shared.orders

import com.eaglepoint.task136.shared.db.OrderDao
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.datetime.Clock
import kotlinx.datetime.Instant
import kotlin.time.Duration
import kotlin.time.Duration.Companion.days
import kotlin.time.Duration.Companion.minutes

data class TimeWindow(
    val start: Instant,
    val end: Instant,
)

class BookingUseCase(
    private val orderDao: OrderDao,
    private val clock: Clock,
    private val buffer: Duration = 10.minutes,
) {
    suspend fun findThreeAvailableSlots(
        resourceId: String,
        duration: Duration,
        anchor: Instant = clock.now(),
    ): List<TimeWindow> = withContext(Dispatchers.IO) {
        val existing = orderDao.getActiveByResource(resourceId)
            .map { TimeWindow(Instant.fromEpochMilliseconds(it.startTime), Instant.fromEpochMilliseconds(it.endTime)) }
            .sortedBy { it.start }

        val horizonEnd = anchor.plus(14.days)
        val results = mutableListOf<TimeWindow>()
        var cursor = anchor

        while (cursor < horizonEnd && results.size < 3) {
            val candidate = TimeWindow(cursor, cursor.plus(duration))
            if (!overlaps(existing, candidate)) {
                results += candidate
                cursor = cursor.plus(30.minutes)
            } else {
                cursor = cursor.plus(10.minutes)
            }
        }

        results
    }

    fun overlaps(existing: List<TimeWindow>, candidate: TimeWindow): Boolean {
        val bufferedCandidateStart = candidate.start.minus(buffer)
        val bufferedCandidateEnd = candidate.end.plus(buffer)

        return existing.any { slot ->
            val bufferedSlotStart = slot.start.minus(buffer)
            val bufferedSlotEnd = slot.end.plus(buffer)
            bufferedCandidateStart < bufferedSlotEnd && bufferedCandidateEnd > bufferedSlotStart
        }
    }
}

