import com.eaglepoint.task136.shared.viewmodel.ResourceListViewModel

@Composable
fun ResourceListScreen(viewModel: ResourceListViewModel) {
    val state by viewModel.state.collectAsState()

    LaunchedEffect(Unit) {
        viewModel.loadPage(limit = 5000)
    }

    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("Resources", style = MaterialTheme.typography.headlineMedium)
        LazyColumn(modifier = Modifier.fillMaxSize()) {
            items(
                items = state.resources,
                key = { it.id },
                contentType = { "resource_row" },
            ) { resource ->
                Text(
                    text = "${resource.name} (${resource.availableUnits})",
                    style = MaterialTheme.typography.bodyLarge,
                    modifier = Modifier.padding(vertical = 6.dp),
                )
            }
        }
    }
}

