import com.eaglepoint.task136.shared.db.ResourceDao
import com.eaglepoint.task136.shared.db.ResourceEntity

class FakeResourceDao : ResourceDao {
    private val rows = (1..5000).map {
        ResourceEntity(
            id = "res-$it",
            name = "Resource $it",
            category = "General",
            availableUnits = it % 12,
            unitPrice = (it % 200) + 0.99,
        )
    }.associateBy { it.id }.toMutableMap()

    override suspend fun upsert(resource: ResourceEntity) {
        rows[resource.id] = resource
    }

    override suspend fun update(resource: ResourceEntity) {
        rows[resource.id] = resource
    }

    override suspend fun getById(id: String): ResourceEntity? = rows[id]

    override suspend fun page(limit: Int, offset: Int): List<ResourceEntity> {
        return rows.values.drop(offset).take(limit)
    }
}

