import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import com.eaglepoint.task136.shared.viewmodel.OrderWorkflowViewModel
import com.eaglepoint.task136.shared.viewmodel.ResourceListViewModel

@Composable
fun ResourceListScreen(
    viewModel: ResourceListViewModel,
    orderWorkflowViewModel: OrderWorkflowViewModel,
    roleLabel: String,
    onActivity: () -> Unit,
    onLogout: () -> Unit,
) {
    val state by viewModel.state.collectAsState()
    val orderState by orderWorkflowViewModel.state.collectAsState()

    LaunchedEffect(Unit) {
        viewModel.loadPage(limit = 5000)
        onActivity()
    }

    val atmosphere = Brush.verticalGradient(
        colors = listOf(
            Color(0xFFD6F0EB),
            Color(0xFFF4F3E8),
            Color(0xFFFFFDF8),
        ),
    )

    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(atmosphere)
            .padding(16.dp),
    ) {
        Row(
            modifier = Modifier.fillMaxWidth(),
            verticalAlignment = Alignment.CenterVertically,
        ) {
            Column(modifier = Modifier.fillMaxWidth(0.7f)) {
                Text("Resources", style = MaterialTheme.typography.headlineMedium)
                Text(
                    text = "Role: $roleLabel",
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onBackground.copy(alpha = 0.75f),
                )
            }
            TextButton(onClick = onLogout) {
                Text("Logout")
            }
        }

        Spacer(Modifier.height(12.dp))

        Surface(
            modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(18.dp)),
            color = MaterialTheme.colorScheme.surface.copy(alpha = 0.9f),
            tonalElevation = 3.dp,
            shadowElevation = 4.dp,
        ) {
            Row(
                modifier = Modifier.fillMaxWidth().padding(horizontal = 14.dp, vertical = 12.dp),
                verticalAlignment = Alignment.CenterVertically,
            ) {
                Text(
                    text = "${state.resources.size} resources loaded",
                    style = MaterialTheme.typography.titleLarge,
                    color = MaterialTheme.colorScheme.primary,
                )
            }
        }

        Spacer(Modifier.height(12.dp))

        Surface(
            modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(18.dp)),
            color = MaterialTheme.colorScheme.surface.copy(alpha = 0.92f),
            tonalElevation = 3.dp,
            shadowElevation = 3.dp,
        ) {
            Column(modifier = Modifier.fillMaxWidth().padding(12.dp)) {
                Text("Order Workflow", style = MaterialTheme.typography.titleLarge)
                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    Button(onClick = {
                        orderWorkflowViewModel.createPendingTenderDemo()
                        onActivity()
                    }) {
                        Text("Create Pending")
                    }
                    Button(onClick = {
                        orderWorkflowViewModel.confirmLastOrder()
                        onActivity()
                    }) {
                        Text("Confirm")
                    }
                }
                Spacer(Modifier.height(8.dp))
                Button(onClick = {
                    orderWorkflowViewModel.suggestSlots()
                    onActivity()
                }) {
                    Text("Suggest 3 Slots")
                }
                if (orderState.lastOrderId != null) {
                    Text(
                        text = "Last: ${orderState.lastOrderId} (${orderState.lastOrderState.orEmpty()})",
                        style = MaterialTheme.typography.bodyMedium,
                    )
                }
                orderState.suggestedSlots.forEach { slot ->
                    Text("- $slot", style = MaterialTheme.typography.bodyMedium)
                }
            }
        }

        Spacer(Modifier.height(12.dp))

        if (state.isLoading) {
            Row(modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically) {
                CircularProgressIndicator(strokeWidth = 2.dp)
                Text(
                    text = "  Loading catalog...",
                    style = MaterialTheme.typography.bodyLarge,
                )
            }
        }

        Spacer(Modifier.height(8.dp))

        LazyColumn(modifier = Modifier.fillMaxSize()) {
            items(
                items = state.resources,
                key = { it.id },
                contentType = { "resource_row" },
            ) { resource ->
                Card(
                    shape = RoundedCornerShape(16.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.93f),
                    ),
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 5.dp),
                ) {
                    Row(modifier = Modifier.fillMaxWidth().padding(12.dp), verticalAlignment = Alignment.CenterVertically) {
                        Column(modifier = Modifier.fillMaxWidth(0.72f)) {
                            Text(
                                text = resource.name,
                                style = MaterialTheme.typography.titleLarge,
                                fontWeight = FontWeight.SemiBold,
                            )
                            Text(
                                text = "Category: ${resource.category}",
                                style = MaterialTheme.typography.bodyMedium,
                                color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.7f),
                            )
                        }
                        Text(
                            text = if (roleLabel == "Viewer") "Read-only" else "${resource.availableUnits} units",
                            style = MaterialTheme.typography.bodyLarge,
                            color = MaterialTheme.colorScheme.tertiary,
                        )
                    }
                }
            }
        }
    }
}

