                },
                actorId = authState.principal?.userId.orEmpty(),
            )
        } else {
            LoginScreen(
                state = authState,
                onUsernameChange = authViewModel::updateUsername,
                onPasswordChange = authViewModel::updatePassword,
                onLoginClick = authViewModel::login,
            )
        }
    }
}

