                    Button(onClick = {
                        orderWorkflowViewModel.createPendingTenderDemo()
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Create Pending")
                    }
                    Button(onClick = {
                        orderWorkflowViewModel.confirmLastOrder()
                        onActivity()
                    }, enabled = canManageOrders) {
                        Text("Confirm")
                    }
                }
                Spacer(Modifier.height(8.dp))
                Button(onClick = {
                    orderWorkflowViewModel.suggestSlots()
                    onActivity()
                }, enabled = canManageOrders) {
                    Text("Suggest 3 Slots")
                }
                if (!canManageOrders) {
                    Text(
                        text = "Order actions are restricted for Viewer role.",
                        style = MaterialTheme.typography.bodyMedium,
                        color = MaterialTheme.colorScheme.error,
                    )
                }
                if (orderState.lastOrderId != null) {
                    Text(
