package com.eaglepoint.task136.shared.rbac

import kotlin.test.Test
import kotlin.test.assertFalse
import kotlin.test.assertTrue

class AbacPolicyEvaluatorTest {
    private val evaluator = AbacPolicyEvaluator()

    @Test
    fun `admin can read invoice tax on trusted device`() {
        val allowed = evaluator.canReadInvoiceTaxField(
            role = Role.Admin,
            context = AccessContext("admin", "admin", isDelegate = false, deviceTrusted = true),
        )
        assertTrue(allowed)
    }

    @Test
    fun `viewer cannot issue refunds`() {
        val allowed = evaluator.canIssueRefund(
            role = Role.Viewer,
            context = AccessContext("viewer", "viewer", isDelegate = false, deviceTrusted = true),
        )
        assertFalse(allowed)
    }
}

package com.eaglepoint.task136.shared.viewmodel

import com.eaglepoint.task136.shared.services.ValidationService
import kotlinx.datetime.Clock
import kotlinx.datetime.Instant
import kotlin.test.Test
import kotlin.test.assertEquals

class MeetingWorkflowViewModelTest {
    @Test
    fun `meeting moves through submit approve checkin`() {
        val clock = FixedMeetingClock(Instant.parse("2026-03-30T10:00:00Z"))
        val vm = MeetingWorkflowViewModel(
            validationService = ValidationService(clock),
            clock = clock,
        )

        vm.submitMeeting(clock.now())
        vm.approve()
        vm.checkIn()

        assertEquals(MeetingStatus.CheckedIn, vm.state.value.status)
    }
}

private class FixedMeetingClock(var current: Instant) : Clock {
    override fun now(): Instant = current
}

package com.eaglepoint.task136.shared.viewmodel

import com.eaglepoint.task136.shared.rbac.AbacPolicyEvaluator
import com.eaglepoint.task136.shared.rbac.Role
import kotlin.test.Test
import kotlin.test.assertEquals

class OrderFinanceViewModelTest {
    @Test
    fun `admin can generate taxed invoice and refund`() {
        val vm = OrderFinanceViewModel(AbacPolicyEvaluator())
        vm.addDemoItem()
        vm.generateInvoice(Role.Admin, "admin")
        vm.refundLatest(Role.Admin, "admin")

        assertEquals(1, vm.state.value.invoices.size)
        assertEquals(1, vm.state.value.refunds.size)
    }

    @Test
    fun `viewer refund denied`() {
        val vm = OrderFinanceViewModel(AbacPolicyEvaluator())
        vm.addDemoItem()
        vm.generateInvoice(Role.Viewer, "viewer")
        vm.refundLatest(Role.Viewer, "viewer")

        assertEquals("Refund denied for role", vm.state.value.note)
